import sys
input = sys.stdin.read

def main():
    data = input().split()
    N = int(data[0])
    S = data[1]

    # Define the winning move for each Aoki's move
    win_move = {'R': 'P', 'P': 'S', 'S': 'R'}

    # Define the losing move for each Aoki's move
    lose_move = {'R': 'S', 'P': 'R', 'S': 'P'}

    # DP table: dp[i][m] = max wins up to i-th game with move m
    # m can be 'R', 'P', 'S'
    dp = [{} for _ in range(N)]

    # Initialize the first move
    for move in ['R', 'P', 'S']:
        if move != win_move[S[0]] and move != lose_move[S[0]]:
            # Takahashi must not lose, so this move is invalid
            continue
        dp[0][move] = 1 if move == win_move[S[0]] else 0

    # Fill the DP table
    for i in range(1, N):
        for prev_move in ['R', 'P', 'S']:
            if prev_move not in dp[i-1]:
                continue
            for curr_move in ['R', 'P', 'S']:
                if curr_move == prev_move:
                    continue  # Consecutive moves must be different
                # Check if Takahashi loses
                if curr_move == lose_move[S[i]]:
                    continue
                # Update dp[i][curr_move]
                dp[i][curr_move] = max(dp[i].get(curr_move, 0), dp[i-1][prev_move] + (1 if curr_move == win_move[S[i]] else 0))

    # Find the maximum number of wins in the last game
    print(max(dp[N-1].values()))

main()
